import mysql.connector
import os

def import_data_with_load_infile(host, user, password, database, table_name, file_path, fields_terminated_by=',', lines_terminated_by='\n', enclosed_by='"', optionally_enclosed=False, ignore_lines=1):
    """
    Imports data into a MySQL table using LOAD DATA INFILE.

    Args:
        host (str): MySQL host.
        user (str): MySQL username.
        password (str): MySQL password.
        database (str): MySQL database name.
        table_name (str): The name of the table to import data into.
        file_path (str): The path to the data file.
        fields_terminated_by (str): The character that separates fields (default: ',').
        lines_terminated_by (str): The character that separates lines (default: '\n').
        enclosed_by (str): The character that encloses fields (default: '"').
        optionally_enclosed (bool): True if fields are optionally enclosed, False otherwise.
        ignore_lines (int): Number of lines to ignore at the beginning of the file (e.g., header).
    """
    if not os.path.exists(file_path):
        print(f"Error: File not found at '{file_path}'")
        return

    try:
        # Establish database connection with local_infile=True
        cnx = mysql.connector.connect(
            host=host,
            user=user,
            password=password,
            database=database,
            allow_local_infile=True  # Important: Enable local_infile
        )
        cursor = cnx.cursor()

        # Construct the LOAD DATA INFILE statement
        load_data_sql = f"""
        LOAD DATA INFILE '{file_path.replace("\\", "/")}'
        INTO TABLE {table_name}
        FIELDS TERMINATED BY '{fields_terminated_by}'
        {'OPTIONALLY' if optionally_enclosed else ''} ENCLOSED BY '{enclosed_by}'
        LINES TERMINATED BY '{lines_terminated_by}'
        IGNORE {ignore_lines} LINES;
        """

        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        cnx.commit()
        print(f"Successfully imported data from '{file_path}' into table '{table_name}'.")

    except mysql.connector.Error as err:
        print(f"MySQL Error: {err}")
        print("Please ensure 'local_infile=1' is enabled in your MySQL server configuration (my.cnf or my.ini).")
        print("For example, add 'local-infile=1' under the [mysqld] section and restart the MySQL service.")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if 'cnx' in locals() and cnx.is_connected():
            cursor.close()
            cnx.close()
            print("MySQL connection closed.")

